import React, { useState, useEffect } from 'react';
import { cities, places, trips } from '../utils/api';

const AllPlaces = () => {
  const [cityList, setCityList] = useState([]);
  const [allPlaces, setAllPlaces] = useState([]);
  const [selectedCity, setSelectedCity] = useState('ALL');
  const [selectedType, setSelectedType] = useState('ALL');
  const [filteredPlaces, setFilteredPlaces] = useState([]);
  const [showTripForm, setShowTripForm] = useState(false);
  const [selectedPlace, setSelectedPlace] = useState(null);
  const [tripData, setTripData] = useState({ name: '', budget: '' });

  useEffect(() => {
    fetchCities();
    fetchAllPlaces();
  }, []);

  useEffect(() => {
    filterPlaces();
  }, [allPlaces, selectedCity, selectedType]);

  const fetchCities = async () => {
    try {
      const response = await cities.getAll();
      setCityList(response.data);
    } catch (error) {
      console.error('Failed to fetch cities:', error);
    }
  };

  const fetchAllPlaces = async () => {
    try {
      const response = await cities.getAll();
      const allCityPlaces = [];

      for (const city of response.data) {
        try {
          const placesResponse = await places.getByCity(city.id);
          const placesWithCity = placesResponse.data.map(place => ({
            ...place,
            city_name: city.name
          }));
          allCityPlaces.push(...placesWithCity);
        } catch (error) {
          console.error(`Failed to fetch places for ${city.name}:`, error);
        }
      }

      setAllPlaces(allCityPlaces);
    } catch (error) {
      console.error('Failed to fetch places:', error);
    }
  };

  const filterPlaces = () => {
    let filtered = allPlaces;

    if (selectedCity !== 'ALL') {
      filtered = filtered.filter(place => place.city_id == selectedCity);
    }

    if (selectedType !== 'ALL') {
      filtered = filtered.filter(place => place.type === selectedType);
    }

    setFilteredPlaces(filtered);
  };

  const getTypeColor = (type) => {
    switch (type) {
      case 'HOTEL': return '#3b82f6';
      case 'RESTAURANT': return '#ef4444';
      case 'ATTRACTION': return '#10b981';
      default: return '#6b7280';
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>Explore Places</h1>
        <div style={styles.filters}>
          <select 
            value={selectedCity} 
            onChange={(e) => setSelectedCity(e.target.value)}
            style={styles.filterSelect}
          >
            <option value="ALL">All Cities</option>
            {cityList.map(city => (
              <option key={city.id} value={city.id}>{city.name}</option>
            ))}
          </select>
          <select 
            value={selectedType} 
            onChange={(e) => setSelectedType(e.target.value)}
            style={styles.filterSelect}
          >
            <option value="ALL">All Types</option>
            <option value="HOTEL">Hotels</option>
            <option value="RESTAURANT">Restaurants</option>
            <option value="ATTRACTION">Attractions</option>
          </select>
        </div>
      </div>

      <div style={styles.placesGrid}>
        {filteredPlaces.map(place => (
          <div key={place.id} style={styles.placeCard}>
            <div style={styles.imageContainer}>
              {place.image_url ? (
                <img 
                  src={`http://localhost:5000${place.image_url}`} 
                  alt={place.name}
                  style={styles.placeImage}
                />
              ) : (
                <div style={styles.imagePlaceholder}>
                  📷
                </div>
              )}
            </div>
            <div style={styles.cardContent}>
              <div style={styles.cardHeader}>
                <h3 style={styles.placeName}>{place.name}</h3>
                <span style={{...styles.typeTag, backgroundColor: getTypeColor(place.type)}}>
                  {place.type}
                </span>
              </div>
              <p style={styles.cityName}>{place.city_name}</p>
              {place.description && (
                <p style={styles.description}>{place.description}</p>
              )}
              <div style={styles.cardFooter}>
                <div style={styles.price}>NPR {place.price}</div>
                <div style={styles.rating}>★ {place.rating}</div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredPlaces.length === 0 && (
        <div style={styles.noResults}>
          <h3>No places found</h3>
          <p>Try adjusting your filters to see more results.</p>
        </div>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem',
    backgroundColor: '#f8fafc',
    minHeight: '100vh'
  },
  header: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
    marginBottom: '2rem',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    flexWrap: 'wrap',
    gap: '1rem'
  },
  title: {
    color: '#1f2937',
    fontSize: '2.5rem',
    fontWeight: '700',
    margin: 0
  },
  filters: {
    display: 'flex',
    gap: '1rem',
    alignItems: 'center'
  },
  filterSelect: {
    padding: '0.75rem 1rem',
    border: '2px solid #e5e7eb',
    borderRadius: '8px',
    backgroundColor: 'white',
    fontSize: '0.95rem',
    fontWeight: '500',
    color: '#374151',
    cursor: 'pointer',
    transition: 'all 0.2s',
    minWidth: '140px'
  },
  placesGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '2rem',
    marginBottom: '2rem'
  },
  placeCard: {
    backgroundColor: 'white',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
    overflow: 'hidden',
    transition: 'transform 0.2s, box-shadow 0.2s',
    cursor: 'pointer'
  },
  imageContainer: {
    width: '100%',
    height: '200px',
    overflow: 'hidden'
  },
  placeImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover'
  },
  imagePlaceholder: {
    width: '100%',
    height: '100%',
    backgroundColor: '#f3f4f6',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '3rem',
    color: '#9ca3af'
  },
  cardContent: {
    padding: '1.5rem'
  },
  cardHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'flex-start',
    marginBottom: '0.5rem'
  },
  placeName: {
    fontSize: '1.25rem',
    fontWeight: '700',
    color: '#1f2937',
    margin: 0,
    flex: 1
  },
  typeTag: {
    color: 'white',
    padding: '0.25rem 0.5rem',
    borderRadius: '12px',
    fontSize: '0.75rem',
    fontWeight: '700',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
    marginLeft: '0.5rem'
  },
  cityName: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: '0 0 1rem 0',
    fontWeight: '500'
  },
  description: {
    color: '#4b5563',
    fontSize: '0.9rem',
    lineHeight: '1.5',
    margin: '0 0 1rem 0'
  },
  cardFooter: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingTop: '1rem',
    borderTop: '1px solid #f3f4f6'
  },
  price: {
    fontSize: '1.1rem',
    fontWeight: '700',
    color: '#059669'
  },
  rating: {
    fontSize: '1rem',
    fontWeight: '600',
    color: '#f59e0b'
  },
  noResults: {
    textAlign: 'center',
    padding: '3rem',
    backgroundColor: 'white',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  }
};

export default AllPlaces;
